<?php
namespace App\Services; use App\Models\Module; use Illuminate\Support\Facades\File; use Illuminate\Support\Facades\Log; use RuntimeException;
class ModuleManager { public function discover():int{$count=0;foreach(File::glob(base_path('modules/*/module.json')) as $path){try{$m=json_decode(File::get($path),true,flags:JSON_THROW_ON_ERROR);$this->validate($m,$path);Module::updateOrCreate(['slug'=>$m['slug']],['name'=>$m['name'],'version'=>$m['version'],'author'=>$m['author']??null,'description'=>$m['description']??null,'manifest'=>$m]);$count++;}catch(\Throwable $e){Log::error('Invalid NEXUS module',['path'=>$path,'error'=>$e->getMessage()]);}}return $count;} private function validate(array $m,string $path):void{foreach(['slug','name','version'] as $key)if(empty($m[$key]))throw new RuntimeException("Missing {$key} in {$path}");if(!preg_match('/^[a-z0-9-]+$/',$m['slug']))throw new RuntimeException('Invalid module slug');} public function toggle(Module $module):void{$module->update(['enabled'=>!$module->enabled,'installed_at'=>$module->installed_at??now()]);} }
